// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring the instantaneous electrical current of the AX1 motor."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder providing the shaft position of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder mounted behind the gearwheel gearbox delivering the intermediate gearbox position."
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

// C4: Physical-to‑virtual interaction (DataTransmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// C10: Data (stored as DataPoints)
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑stamped data points of motor current streamed via MQTT."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MqttBrokerEnabler, ModelExecutionEngineEnabler
]

instance MotorPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped data points of motor shaft angle streamed via MQTT."
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo MqttBrokerEnabler, ModelExecutionEngineEnabler
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped data points of gearbox output angle streamed via MQTT."
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo MqttBrokerEnabler, ModelExecutionEngineEnabler
]

// C10: Models / Data (simulation & analytical friction models)
instance SysMLMotorBlockModel : DTDFVocab:Model [
    base:desc "SysML block‑definition diagram of the AX1 permanent‑magnet synchronous motor."
    DTDFVocab:inputTo ModelExecutionEngineEnabler
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the gearwheel and cycloidal gearbox."
    DTDFVocab:inputTo ModelExecutionEngineEnabler
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Coulomb‑viscous friction model."
    DTDFVocab:inputTo ParameterIdentificationEngineEnabler
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Stribeck friction model."
    DTDFVocab:inputTo ParameterIdentificationEngineEnabler
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Dahl friction model."
    DTDFVocab:inputTo ParameterIdentificationEngineEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "Data‑driven black‑box LuGre friction model."
    DTDFVocab:inputTo ParameterIdentificationEngineEnabler
]

// C11: Enablers
instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker handling live sensor data streaming as time‑stamped traces."
    DTDFVocab:enables LiveSensorStreamingService
]

instance ModelExecutionEngineEnabler : DTDFVocab:Enabler [
    base:desc "Execution engine running SysML and Simulink simulation models in real time."
    DTDFVocab:enables FrictionParameterIdentificationService, SimulationComparisonService
]

instance DashboardEngineEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard application for real‑time visualisation of measured and simulated data."
    DTDFVocab:enables RealTimeDashboardVisualizationService
]

instance ParameterIdentificationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Processing component that identifies static, kinetic and viscous friction parameters from data."
    DTDFVocab:enables FrictionParameterIdentificationService
]

instance SimulationComparisonEngineEnabler : DTDFVocab:Enabler [
    base:desc "Component that compares simulated versus measured data traces."
    DTDFVocab:enables SimulationComparisonService
]

instance ModelUpdateEngineEnabler : DTDFVocab:Enabler [
    base:desc "Component that generates updated friction models and publishes them to the robot controller."
    DTDFVocab:enables FrictionModelUpdateService
]

// C6: Services
instance LiveSensorStreamingService : DTDFVocab:Service [
    base:desc "Service that streams live sensor data (current, positions) via MQTT into the digital shadow."
    DTDFVocab:provides InsightLiveDataAvailability
]

instance RealTimeDashboardVisualizationService : DTDFVocab:Service [
    base:desc "Service providing real‑time visualisation of measured and simulated traces on a web dashboard."
