]

instance SimulationComparisonService : DTDFVocab:Service [
    base:desc "Service that compares simulated data against measured traces to detect model deviations."
    DTDFVocab:provides InsightSimulationVsMeasuredDeviation
]

instance FrictionModelUpdateService : DTDFVocab:Service [
    base:desc "Service that generates and deploys updated friction models to the robot controller for motion accuracy improvement."
    DTDFVocab:provides ActionImproveMotionAccuracy
]

// C17: Insights
instance InsightLiveDataAvailability : DTDFVocab:Insight [
    base:desc "Insight indicating that live sensor data are successfully ingested into the digital shadow."
