instance InsightIdentifiedFrictionParameters : DTDFVocab:Insight [
    base:desc "Insight presenting the currently identified static, kinetic and viscous friction parameters."
]

instance InsightSimulationVsMeasuredDeviation : DTDFVocab:Insight [
    base:desc "Insight highlighting deviations between simulated and measured data traces."
